let ME=null, PRESTADORES=[], SIGTAP=[], AUX={}, TETOS=[];
const $=s=>document.querySelector(s); const app=$('#app');
const norm = s => String(s||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/\s+/g,' ').trim().toUpperCase();
async function api(url,opt={}){const r=await fetch(url,{headers:{'Content-Type':'application/json'},...opt}); if(!r.ok){let e=await r.json().catch(()=>({erro:r.statusText})); throw new Error(e.erro||'Erro')} return r.headers.get('content-type')?.includes('json')?r.json():r.text()}
function fmt(d){return d?String(d).split('-').reverse().join('/'):''}
function mesLabel(v){const [y,m]=String(v||'').slice(0,7).split('-');const nomes=['janeiro','fevereiro','março','abril','maio','junho','julho','agosto','setembro','outubro','novembro','dezembro'];return y&&m?`${nomes[Number(m)-1]||m} de ${y}`:String(v||'')}
function cell(v){if(v===null||v===undefined)return '';if(typeof v==='string'&&/^\d{4}-\d{2}$/.test(v))return mesLabel(v);if(typeof v==='string'&&/^\d{4}-\d{2}-\d{2}T/.test(v)){try{return new Date(v).toLocaleString('pt-BR')}catch(e){return v}}if(typeof v==='string'&&/^\d{4}-\d{2}-\d{2}$/.test(v))return fmt(v);return v}

function moeda(v){const n=Number(String(v||'').replace(/[^0-9,.-]/g,'').replace(/\./g,'').replace(',','.'));return Number.isFinite(n)&&n>0?n.toLocaleString('pt-BR',{style:'currency',currency:'BRL'}):(v?esc(v):'Não informado')}
function moneyInput(v){const cents=String(v||'').replace(/\D/g,'');const n=(Number(cents||0)/100);return n.toLocaleString('pt-BR',{style:'currency',currency:'BRL'});}
function bindMoneyMask(id){const el=document.getElementById(id); if(!el) return; if(el.value) el.value=moeda(el.value).replace('Não informado',''); el.addEventListener('input',()=>{el.value=moneyInput(el.value);});}
function diasAte(data){if(!data)return null;const d=new Date(data+'T12:00:00');return Math.ceil((d-new Date())/86400000)}
function statusContrato(data){const dias=diasAte(data);if(dias===null)return{label:'Sem vigência',cls:'sem-data',dias:null,icon:'⚪'};if(dias<0)return{label:'Vencido',cls:'vencido',dias,icon:'🟥'};if(dias<=90)return{label:'Vencendo',cls:'vencendo',dias,icon:'🟧'};return{label:'Vigente',cls:'vigente',dias,icon:'🟩'}}
function listaContratos(){const rows=[];PRESTADORES.forEach(p=>(p.instrumentos||[]).forEach(i=>rows.push({p,i,st:statusContrato(i.vigenciaFim)})));return rows.sort((a,b)=>(a.st.dias??99999)-(b.st.dias??99999)||String(a.p.nome).localeCompare(String(b.p.nome),'pt-BR'))}
function resumoContratos(){const rows=listaContratos();return{total:rows.length,vencidos:rows.filter(x=>x.st.cls==='vencido').length,vencendo:rows.filter(x=>x.st.cls==='vencendo').length,vigentes:rows.filter(x=>['vigente','vencendo'].includes(x.st.cls)).length,semData:rows.filter(x=>x.st.cls==='sem-data').length,valor:rows.reduce((s,x)=>{let n=Number(String(x.i.valorGlobal||'').replace(/[^0-9,.-]/g,'').replace(/\./g,'').replace(',','.'));return s+(Number.isFinite(n)?n:0)},0)}}
function panoramaRedeAssistencial(){
  const contratos=listaContratos();
  const unidades=new Set(PRESTADORES.filter(p=>p.ativo!==false).map(p=>p.id));
  const municipios=new Set(PRESTADORES.filter(p=>p.ativo!==false&&p.municipio).map(p=>p.municipio));
  const servicos=contratos.filter(x=>x.i?.ativo!==false).length;
  const porNatureza={};
  contratos.forEach(({i})=>{ const n=String(i.natureza||'CONTRATUALIZADA').toUpperCase(); if(!porNatureza[n]) porNatureza[n]={contratos:0,servicos:0}; porNatureza[n].contratos++; porNatureza[n].servicos++; });
  return {unidades:unidades.size, municipios:municipios.size, servicos, porNatureza};
}
function renderPanoramaRede(){
  const p=panoramaRedeAssistencial();
  const rows=Object.entries(p.porNatureza).sort((a,b)=>a[0].localeCompare(b[0],'pt-BR')).map(([n,v])=>`<tr><td>${esc(n)}</td><td>${v.contratos}</td><td>${v.servicos}</td></tr>`).join('')||'<tr><td colspan="3">Nenhum registro.</td></tr>';
  return `<div class="kpi-grid compact-kpis"><div class="kpi"><span>Unidades executantes</span><b>${p.unidades}</b></div><div class="kpi"><span>Serviços ativos</span><b>${p.servicos}</b></div><div class="kpi"><span>Municípios cobertos</span><b>${p.municipios}</b></div><div class="kpi green"><span>Contratos vigentes</span><b>${resumoContratos().vigentes}</b></div></div><div class="card compact-card"><div class="section-head"><div><h3>Panorama da Rede Assistencial</h3><p class="muted">Resumo por natureza da rede, sem poluir a tela.</p></div></div><table class="mini-table"><thead><tr><th>Natureza</th><th>Contratos</th><th>Serviços</th></tr></thead><tbody>${rows}</tbody></table></div>`;
}
function showContratosPopupOnce(alertas){
  if(!alertas?.length || sessionStorage.getItem('sigoa_alerta_contratos_v22_4_visto')) return;
  sessionStorage.setItem('sigoa_alerta_contratos_v22_4_visto','1');
  const linhas=alertas.map(x=>`<tr><td><b>${esc(x.p.nome)}</b></td><td>${esc(x.i.servico||'-')}</td><td>${fmt(x.i.vigenciaFim)}</td><td>${x.st.dias<0?Math.abs(x.st.dias)+' dias vencido':x.st.dias+' dias'}</td></tr>`).join('');
  openModal(`<div class="modal-head"><div><span class="eyebrow">Alerta contratual</span><h2>⚠️ Contratos vigentes próximos do vencimento</h2><p class="muted">Lista exibida apenas ao entrar. Depois consulte em Gestão de Contratos.</p></div><button class="ghost" onclick="closeModal()">Fechar</button></div><div class="table-wrap"><table><thead><tr><th>Prestador</th><th>Serviço</th><th>Fim da vigência</th><th>Situação</th></tr></thead><tbody>${linhas}</tbody></table></div><div class="modal-actions"><button onclick="closeModal();prestadores();setTimeout(()=>{document.querySelector('#fStatus').value='vencendo';filtrarContratos()},80)">Ver contratos a vencer</button><button class="ghost" onclick="closeModal()">Fechar</button></div>`);
}
function renderAnexosDocumentos(anexos){
  const arr=Array.isArray(anexos)?anexos:[];
  if(!arr.length) return '<p class="muted">Nenhum anexo/link cadastrado.</p>';
  const linhas=arr.map((a,idx)=>{
    let item=typeof a==='string'?{url:a,nome:a,tipo:'Link'}:a;
    const url=item.url||item.link||item.caminho||item.nome||'';
    const nome=item.nome||item.titulo||url;
    const tipo=item.tipo||item.categoria||'Documento';
    const clickable=/^https?:\/\//i.test(url);
    return `<tr><td>${esc(tipo)}</td><td>${clickable?`<a href="${esc(url)}" target="_blank" rel="noopener">${esc(nome)}</a>`:esc(nome)}</td><td>${clickable?`<a class="link-action" href="${esc(url)}" target="_blank" rel="noopener">Abrir</a>`:'-'}</td></tr>`;
  }).join('');
  return `<table class="mini-table"><thead><tr><th>Tipo</th><th>Documento/Link</th><th>Ação</th></tr></thead><tbody>${linhas}</tbody></table>`;
}


function normalizeAnexos(anexos){
  if(!Array.isArray(anexos)) return [];
  return anexos.map(a=>typeof a==='string'?{tipo:'Link externo',nome:a,url:a}:a).filter(Boolean);
}
const DOC_TIPOS=['Contrato Principal','Termo de Referência','Ordem de Serviço','Termo Aditivo','Notificação','Outros'];
function renderDocumentEditor(anexos){
  const arr=normalizeAnexos(anexos);
  const rows=arr.map((a,idx)=>`<tr><td><select class="docTipo">${DOC_TIPOS.map(t=>`<option ${String(a.tipo||'')===t?'selected':''}>${t}</option>`).join('')}</select></td><td><input class="docNome" value="${esc(a.nome||'')}" placeholder="Ex.: Contrato 565/2026"></td><td><input class="docUrl" value="${esc(a.url||a.link||a.caminho||'')}" placeholder="Cole link ou caminho do arquivo"></td><td><button class="danger" onclick="this.closest('tr').remove()">Excluir</button></td></tr>`).join('');
  return `<div class="doc-panel"><div class="section-head"><div><h3>Documentos contratuais</h3><p class="muted">Cadastre links clicáveis ou caminhos dos arquivos. Quando o banco estiver vinculado, esses metadados ficam persistentes.</p></div><button type="button" onclick="addDocRow()">+ Documento</button></div><div class="table-wrap"><table id="docsTable"><thead><tr><th>Tipo</th><th>Nome</th><th>Link/arquivo</th><th>Ação</th></tr></thead><tbody>${rows}</tbody></table></div></div>`;
}
function addDocRow(){
  const tbody=document.querySelector('#docsTable tbody'); if(!tbody) return;
  const tr=document.createElement('tr');
  tr.innerHTML=`<td><select class="docTipo">${DOC_TIPOS.map(t=>`<option>${t}</option>`).join('')}</select></td><td><input class="docNome" placeholder="Nome do documento"></td><td><input class="docUrl" placeholder="Cole o link/caminho"></td><td><button class="danger" onclick="this.closest('tr').remove()">Excluir</button></td>`;
  tbody.appendChild(tr);
}
function collectDocumentos(){
  return [...document.querySelectorAll('#docsTable tbody tr')].map(tr=>({
    tipo:tr.querySelector('.docTipo')?.value||'Documento',
    nome:tr.querySelector('.docNome')?.value||'',
    url:tr.querySelector('.docUrl')?.value||'',
    data:new Date().toISOString()
  })).filter(x=>x.nome||x.url);
}
function toast(msg,tipo='ok'){
  let t=document.querySelector('#toast'); if(!t){t=document.createElement('div');t.id='toast';document.body.appendChild(t)}
  t.className='toast '+tipo; t.innerHTML=msg; t.style.display='block';
  clearTimeout(window.__toastTimer); window.__toastTimer=setTimeout(()=>t.style.display='none',3200);
}
function confirmarCancelar(cb){
  if(confirm('Deseja descartar as alterações e sair desta tela?')) cb();
}

function openModal(html){let m=document.querySelector('#modal'); if(!m){m=document.createElement('div');m.id='modal';m.className='modal';document.body.appendChild(m)} m.innerHTML=`<div class="modal-bg" onclick="closeModal()"></div><div class="modal-box">${html}</div>`;m.style.display='block'}
function closeModal(){const m=document.querySelector('#modal'); if(m)m.style.display='none'}
function canWrite(){return ['ADMINISTRADOR','OPERADOR'].includes(ME?.perfil)}
function isAdmin(){return ME?.perfil==='ADMINISTRADOR'}
function canAudit(){return ['ADMINISTRADOR','AUDITOR','GESTAO'].includes(ME?.perfil)}
function isConsulta(){return ME?.perfil==='GESTAO'}
function optAux(tipo){return (AUX[tipo]||[]).filter(x=>x.ativo!==false).sort((a,b)=>String(a.nome).localeCompare(String(b.nome),'pt-BR')).map(x=>`<option value="${x.nome}">`).join('')}
function selAux(tipo, id, value=''){return `<input id="${id}" list="dl_${tipo}" value="${value||''}"><datalist id="dl_${tipo}">${optAux(tipo)}</datalist>`}

function esc(v){return String(v??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]))}
function servicosPrestador(p){const arr=[...(p?.instrumentos||[])].map(i=>i.servico).filter(Boolean);return [...new Set(arr)].join(', ')||'Sem tipo de serviço'}
function nomePrestadorServico(p){return `<b>${esc(p.nome)}</b><br><span class="muted">${esc(p.municipio)} • ${esc(servicosPrestador(p))}</span>`}
function optPrestador(p){return `${esc(p.nome)} - ${esc(p.municipio)} - ${esc(servicosPrestador(p))}`}
async function init(){ const m=await api('/api/me'); ME=m.user; if(!ME) return login(); shell(); await load(); dashboard(); }
function login(){app.innerHTML=`<div class="login"><h2>SIGOA</h2><h3>Sistema de Gestão da Oferta Assistencial</h3><p class="muted">Controle de prestadores, ofertas, procedimentos e auditoria.</p><label>Login</label><input id="login" value="admin"><label>Senha</label><input id="senha" type="password" value="admin123"><button onclick="doLogin()">Entrar</button><p id="msg" class="error"></p></div>`}
async function doLogin(){try{await api('/api/login',{method:'POST',body:JSON.stringify({login:$('#login').value,senha:$('#senha').value})}); init()}catch(e){$('#msg').innerText=e.message}}
function shell(){app.innerHTML=`<div class="wrap"><aside class="side pro-side"><div class="brand"><div class="brand-icon">S</div><div><h2>SIGOA</h2><p>Sistema Integrado de Gestão da Oferta Assistencial</p></div></div><div class="userbox"><span>${ME.nome}</span><b>${ME.perfil}</b></div><button onclick="dashboard()">🏠 Dashboard executivo</button>${ME.perfil!=='OPERADOR'?'<button onclick="prestadores()">📄 Gestão de Contratos</button>':''}${canWrite()?'<button onclick="oferta()">🗓️ Gestão de Escalas</button>':''}${isAdmin()?'<button onclick="sigtap()">🧾 Base SIGTAP</button>':''}${canAudit()?'<button onclick="relatorios()">📊 Relatórios</button>':''}${['ADMINISTRADOR','AUDITOR'].includes(ME.perfil)?'<button onclick="auditoria()">🔎 Auditoria</button>':''}${ME.perfil==='ADMINISTRADOR'?'<button onclick="usuarios()">👥 Usuários</button><button onclick="tetosMensais()">🎯 Tetos físicos</button><button onclick="auxiliares()">⚙️ Cadastros auxiliares</button>':''}<div class="side-note"><b>Rede Executora</b><br><span>Consulta externa continua em /rede-executora</span></div><button onclick="perfil()">🔐 Minha senha</button><button onclick="logout()">Sair</button></aside><main class="main" id="main"></main></div>`}
async function load(){
  PRESTADORES=await api('/api/prestadores');
  PRESTADORES=(PRESTADORES||[]).sort((a,b)=>String(a.nome||'').localeCompare(String(b.nome||''),'pt-BR') || String(a.municipio||'').localeCompare(String(b.municipio||''),'pt-BR'));
  PRESTADORES.forEach(p=>{p.instrumentos=(p.instrumentos||[]).sort((a,b)=>String(a.servico||'').localeCompare(String(b.servico||''),'pt-BR') || String(a.numero||a.tipo||'').localeCompare(String(b.numero||b.tipo||''),'pt-BR')); p.instrumentos.forEach(i=>{i.procedimentos=(i.procedimentos||[]).sort((a,b)=>String(a.nome||'').localeCompare(String(b.nome||''),'pt-BR') || String(a.codigo||'').localeCompare(String(b.codigo||''),'pt-BR'));});});
  SIGTAP=(await api('/api/sigtap').catch(()=>[])).sort((a,b)=>String(a.nome||'').localeCompare(String(b.nome||''),'pt-BR') || String(a.codigo||'').localeCompare(String(b.codigo||''),'pt-BR'));
  AUX=await api('/api/auxiliares').catch(()=>({}));
  TETOS=(await api('/api/tetos').catch(()=>[])).sort((a,b)=>String(a.prestador||'').localeCompare(String(b.prestador||''),'pt-BR') || String(a.servico||'').localeCompare(String(b.servico||''),'pt-BR'));
}
async function logout(){await api('/api/logout',{method:'POST'}); ME=null; login()}
function main(html){$('#main').innerHTML=html}
function statusEscalaLabel(st){
  return st==='COMPLETA'?'✅ Completa':st==='PARCIAL'?'⚠️ Parcial':st==='PENDENTE'?'❌ Pendente':'⚪ Sem escala';
}
function statusEscalaClass(st){
  return st==='COMPLETA'?'ok':st==='PARCIAL'?'warn':st==='PENDENTE'?'bad':'muted';
}
function modoLancamentoLabel(m){ return m==='ESCALA_SUBESCALA'?'Escala/Subescala':m==='APENAS_CONTRATUAL'?'Apenas contratual':'Quantitativo mensal'; }
function nomeEscalaPadrao(servico){
  const s=String(servico||'').toUpperCase();
  if(s.includes('DIAGNOSTICO')&&s.includes('RM')) return 'Ressonância Magnética';
  if(s.includes('RESSON')) return 'Ressonância Magnética';
  if(s.includes('DIAGNOSTICO')&&s.includes('TC')) return 'Tomografia Computadorizada';
  if(s.includes('TOMOG')) return 'Tomografia Computadorizada';
  if(s.includes('MAMOG')) return 'Mamografia';
  if(s.includes('ULTRASS')||s.includes('ULTRA-SON')||s.includes('USG')) return 'Ultrassonografia';
  if(s.includes('ELETROENCEF')) return 'Eletroencefalograma';
  return String(servico||'Escala/Oferta principal').replace(/^DIAGN[ÓO]STICO:\s*/i,'').trim() || 'Escala/Oferta principal';
}
function renderSubescalas(e){
  const subs=e.subescalas||[];
  if(!subs.length) return '<div class="muted">Nenhuma escala configurada para este serviço.</div>';
  return `<div class="subesc-list always-open">${subs.map(s=>`<div class="subesc-item ${s.preenchida?'done':'missing'}"><span>${s.preenchida?'✅':'❌'} <b>${esc(s.nome)}</b>${s.observacao?` <span class="muted">${esc(s.observacao)}</span>`:''}</span><span>${s.preenchida?Number(s.quantidade||0).toLocaleString('pt-BR'):'não lançada'}</span></div>`).join('')}</div>`;
}
function renderEscalasCards(rows){ return renderEscalasLista(rows); }
function renderEscalasLista(rows){
  if(!rows.length) return '<div class="card"><p class="muted">Nenhuma escala monitorada para esta competência.</p></div>';
  const ordem={PENDENTE:1,PARCIAL:2,COMPLETA:3,SEM_SUBESCALA:4};
  const ordenadas=[...rows].sort((a,b)=>(ordem[a.status]||9)-(ordem[b.status]||9)||String(a.prestador).localeCompare(String(b.prestador),'pt-BR')||String(a.servico).localeCompare(String(b.servico),'pt-BR'));
  const linhas=ordenadas.map(e=>{
    const escala=(e.subescalas||[]).map(s=>`${s.preenchida?'✅':'❌'} ${esc(s.nome)}${s.preenchida?' - '+Number(s.quantidade||0).toLocaleString('pt-BR'):' - não lançada'}`).join('<br>') || '<span class="muted">Nenhuma escala configurada</span>';
    const searchText=[e.status,e.prestador,e.municipio,e.servico,...((e.subescalas||[]).map(s=>s.nome))].join(' ');
    return `<tr class="escala-row ${statusEscalaClass(e.status)}" data-search="${esc(searchText)}"><td><span class="tag ${statusEscalaClass(e.status)}">${statusEscalaLabel(e.status)}</span></td><td><button class="link-btn" onclick="modalContrato('${e.prestadorId}','${e.instrumentoId}')"><b>${esc(e.prestador)}</b></button></td><td>${esc(e.municipio||'')}</td><td>${esc(e.servico||'-')}</td><td>${escala}</td><td><b>${Number(e.totalOfertaMes||0).toLocaleString('pt-BR')}</b></td></tr>`;
  }).join('');
  return `<div class="card"><div class="section-head"><div><h3>Lista de escalas e subescalas</h3><p class="muted">Pendentes primeiro, depois parciais e completas. Sem cards.</p></div><input class="table-search" placeholder="Filtrar prestador, município ou serviço..." oninput="filtrarTabelaEscalas(this.value)"></div><div class="table-wrap"><table id="tblEscalas"><thead><tr><th>Status</th><th>Prestador</th><th>Município</th><th>Serviço</th><th>Escalas/Subescalas</th><th>Oferta Total</th></tr></thead><tbody>${linhas}</tbody></table></div></div>`;
}
function filtrarTabelaEscalas(q){
  const termo=norm(q);
  const rows=document.querySelectorAll('#tblEscalas tbody tr');
  rows.forEach(tr=>{
    const txt=norm(tr.getAttribute('data-search') || tr.textContent || tr.innerText || '');
    tr.hidden = !!termo && !txt.includes(termo);
    tr.style.display = tr.hidden ? 'none' : '';
  });
}

async function dashboard(){
  await load();
  const mes=new Date().toISOString().slice(0,7);
  const ofertas=await api('/api/ofertas?mes='+mes).catch(()=>[]);
  const escalas=await api('/api/escalas?mes='+mes).catch(()=>[]);
  const totalOferta=ofertas.reduce((s,o)=>s+Number(o.quantidade||0),0);
  const completas=escalas.filter(e=>e.status==='COMPLETA').length;
  const parciais=escalas.filter(e=>e.status==='PARCIAL').length;
  const pendentes=escalas.filter(e=>e.status==='PENDENTE').length;
  const rc=resumoContratos();
  const alertas=listaContratos().filter(x=>x.st.cls==='vencendo').slice(0,30);
  main(`<div class="hero"><div><span class="eyebrow">Painel executivo</span><h1>Painel Executivo</h1><p>Visão gerencial de contratos, rede assistencial e oferta mensal.</p></div><div class="hero-date">Competência<br><b>${mesLabel(mes)}</b></div></div>${renderPanoramaRede()}<div class="kpi-grid"><div class="kpi orange"><span>Vigentes a vencer</span><b>${rc.vencendo}</b></div><div class="kpi red"><span>Contratos vencidos</span><b>${rc.vencidos}</b></div><div class="kpi green"><span>Contratos vigentes</span><b>${rc.vigentes}</b></div><div class="kpi blue"><span>Valor global cadastrado</span><b>${rc.valor.toLocaleString('pt-BR',{style:'currency',currency:'BRL'})}</b></div></div><div class="kpi-grid"><div class="kpi"><span>Oferta lançada no mês</span><b>${totalOferta.toLocaleString('pt-BR')}</b></div><div class="kpi green"><span>Escalas completas</span><b>${completas}</b></div><div class="kpi orange"><span>Escalas parciais</span><b>${parciais}</b></div><div class="kpi red"><span>Escalas pendentes</span><b>${pendentes}</b></div></div>${renderEscalasLista(escalas)}<div class="quick-actions"><button onclick="prestadores()">📄 Gestão de Contratos</button>${canWrite()?'<button onclick="oferta()">🗓️ Lançar escalas</button>':''}<button onclick="relatorios()">📊 Relatórios</button></div>`);
  setTimeout(()=>showContratosPopupOnce(alertas),250);
}
async function prestadores(){
  await load();
  const rc=resumoContratos();
  const rows=listaContratos();
  const tr=rows.map(({p,i,st})=>`<tr class="contract-row ${st.cls}" onclick="modalContrato('${p.id}','${i.id}')"><td><span class="status-pill ${st.cls}">${st.icon} ${st.label}</span></td><td>${esc(i.servico||'-')}<br><span class="muted">${esc(i.natureza||'')}</span></td><td><b>${esc(p.nome)}</b><br><span class="muted">${esc(p.razaoSocial||'')} ${p.cnpj?'• CNPJ '+esc(p.cnpj):''}</span></td><td>${esc(p.municipio||'-')}</td><td>${esc(i.numero||'-')}</td><td>${esc(i.processo||'-')}</td><td>${fmt(i.vigenciaInicio)}<br><b>${fmt(i.vigenciaFim)}</b></td><td>${moeda(i.valorGlobal)}</td><td><button onclick="event.stopPropagation();editarPrestador('${p.id}')">Editar</button></td></tr>`).join('')||'<tr><td colspan="9">Nenhum contrato cadastrado.</td></tr>';
  main(`<div class="hero green-hero"><div><span class="eyebrow">SIGC</span><h1>Gestão de Contratos</h1><p>Contratos, executantes, valores, vigências e rol de procedimentos em um só lugar.</p></div>${isAdmin()?'<button class="big-action" onclick="novoPrestadorModal()">+ Novo contrato</button>':''}</div><div class="kpi-grid"><div class="kpi"><span>Total de contratos</span><b>${rc.total}</b></div><div class="kpi orange"><span>Vencendo em até 90 dias</span><b>${rc.vencendo}</b></div><div class="kpi red"><span>Vencidos</span><b>${rc.vencidos}</b></div><div class="kpi green"><span>Vigentes</span><b>${rc.vigentes}</b></div></div><div class="card filters"><div><h3>Filtros e busca</h3><p class="muted">Localize contratos, processos, executantes ou municípios.</p></div><div class="filter-row"><input id="fBusca" placeholder="Buscar por executante, processo, contrato, município..." oninput="filtrarContratos()"><select id="fStatus" onchange="filtrarContratos()"><option value="">Todos os status</option><option value="vencendo">Vigentes a vencer</option><option value="vencido">Vencido</option><option value="vigente">Vigente</option><option value="sem-data">Sem vigência</option></select><select id="fMun" onchange="filtrarContratos()"><option value="">Todos os municípios</option>${[...new Set(PRESTADORES.map(p=>p.municipio).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'pt-BR')).map(m=>`<option>${esc(m)}</option>`).join('')}</select></div></div><div class="card"><div class="section-head"><div><h3>Contratos cadastrados</h3><p class="muted">Clique em qualquer contrato para ver todos os dados em janela flutuante. Use “Editar” para alterar os campos.</p></div><span class="tag">${rows.length} registro(s)</span></div><div class="table-wrap"><table id="tblContratos"><thead><tr><th>Status</th><th>Categoria</th><th>Executante</th><th>Município</th><th>Contrato</th><th>Processo</th><th>Vigência</th><th>Valor</th><th>Ações</th></tr></thead><tbody>${tr}</tbody></table></div></div>`)
}
function filtrarContratos(){const q=($('#fBusca')?.value||'').toUpperCase();const st=$('#fStatus')?.value||'';const mun=$('#fMun')?.value||'';document.querySelectorAll('#tblContratos tbody tr').forEach(tr=>{const txt=tr.innerText.toUpperCase();const okQ=!q||txt.includes(q);const okS=!st||tr.classList.contains(st);const okM=!mun||txt.includes(mun.toUpperCase());tr.style.display=okQ&&okS&&okM?'':'none'})}
function modalContrato(pid,iid){const p=PRESTADORES.find(x=>x.id===pid);const i=(p?.instrumentos||[]).find(x=>x.id===iid);if(!p||!i)return;const st=statusContrato(i.vigenciaFim);const procs=(i.procedimentos||[]).filter(x=>x.ativo!==false).sort((a,b)=>String(a.nome).localeCompare(String(b.nome),'pt-BR'));const subs=(i.subescalas||[]).filter(x=>x.ativo!==false).sort((a,b)=>String(a.nome).localeCompare(String(b.nome),'pt-BR'));openModal(`<div class="modal-head"><div><span class="status-pill ${st.cls}">${st.icon} ${st.label}</span><h2>${esc(p.nome)}</h2><p>${esc(p.municipio||'')} • ${esc(i.servico||'')}</p></div><button class="ghost" onclick="closeModal()">Fechar</button></div><div class="modal-tabs"><section><h3>Dados da empresa</h3><p><b>Razão social:</b> ${esc(p.razaoSocial||p.nome||'-')}</p><p><b>Nome fantasia:</b> ${esc(p.nomeFantasia||p.nome||'-')}</p><p><b>CNPJ:</b> ${esc(p.cnpj||'-')} &nbsp; <b>CNES:</b> ${esc(p.cnes||'-')}</p><p><b>Contato:</b> ${esc(p.responsavel||'-')} • ${esc(p.telefone||'-')} • ${esc(p.email||'-')}</p><p><b>Endereço:</b> ${esc(p.endereco||'-')}</p></section><section><h3>Contrato</h3><p><b>Número:</b> ${esc(i.numero||'-')} &nbsp; <b>Processo:</b> ${esc(i.processo||'-')}</p><p><b>Natureza:</b> ${esc(i.natureza||'-')} &nbsp; <b>Instrumento:</b> ${esc(i.tipo||'-')}</p><p><b>Valor global:</b> ${moeda(i.valorGlobal)}</p><p><b>Vigência:</b> ${fmt(i.vigenciaInicio)} até <b>${fmt(i.vigenciaFim)}</b></p><p><b>Modo de lançamento:</b> ${modoLancamentoLabel(i.modoLancamento)}</p></section><section><h3>Rol de procedimentos da Rede Executora (${procs.length})</h3>${procs.length?`<input class="table-search" placeholder="Pesquisar no rol..." oninput="filtrarRolModal(this.value)"><div class="table-wrap rol-wrap"><table id="tblRolModal"><thead><tr><th>Código</th><th>Procedimento</th></tr></thead><tbody>${procs.map(pr=>`<tr><td>${esc(pr.codigo)}</td><td>${esc(pr.nome)}</td></tr>`).join('')}</tbody></table></div>`:'<p class="muted">Nenhum procedimento vinculado.</p>'}</section><section><h3>Subescalas para o operador</h3>${subs.length?`<div class="chip-list bluechips">${subs.map(sub=>`<span>${esc(sub.nome)}</span>`).join('')}</div>`:'<p class="muted">Nenhuma subescala cadastrada.</p>'}</section><section><h3>Anexos e links</h3>${renderAnexosDocumentos(i.anexos)}</section></div>${isAdmin()?`<div class="modal-actions"><button onclick="closeModal();editarPrestador('${p.id}')">Editar cadastro completo</button></div>`:''}`)}
function novoPrestadorModal(){
  openModal(`<div class="modal-head"><div><span class="eyebrow">Gestão de Contratos</span><h2>Novo prestador/contrato</h2><p class="muted">Cadastre os dados básicos da empresa. Depois abra o registro para contrato, rol de procedimentos e subescalas.</p></div><button class="ghost" onclick="closeModal()">Fechar</button></div><div class="grid"><div><label>Razão social</label><input id="npRazao"></div><div><label>Nome fantasia/executante</label><input id="npNome"></div><div><label>CNPJ</label><input id="npCnpj"></div><div><label>CNES</label><input id="npCnes"></div><div><label>Município</label>${selAux('municipios','npMun')}</div><div><label>Endereço</label><input id="npEndereco"></div><div><label>Responsável</label><input id="npResp"></div><div><label>Telefone</label><input id="npTel"></div><div><label>E-mail</label><input id="npEmail"></div><div><label>Contato administrativo</label><input id="npContato"></div></div><div class="modal-actions"><button onclick="novoPrestador()">💾 Salvar Alterações</button><button class="btn2" onclick="confirmarCancelar(()=>closeModal())">❌ Cancelar</button></div>`);
}
async function novoPrestador(){
  if(!$('#npNome').value.trim()) return alert('Informe o nome do prestador.');
  await api('/api/prestadores',{method:'POST',body:JSON.stringify({razaoSocial:$('#npRazao')?.value||'',nome:$('#npNome').value||$('#npRazao')?.value, nomeFantasia:$('#npNome').value, municipio:$('#npMun').value, cnpj:$('#npCnpj').value, cnes:$('#npCnes')?.value||'', endereco:$('#npEndereco')?.value||'', responsavel:$('#npResp')?.value||'', telefone:$('#npTel')?.value||'', email:$('#npEmail')?.value||'', contatoAdministrativo:$('#npContato')?.value||''})});
  await load(); closeModal(); toast('✅ Prestador cadastrado com sucesso.'); prestadores();
}
function editarPrestador(id){
  const p=PRESTADORES.find(x=>x.id===id); if(!p) return alert('Prestador não encontrado.');
  const inst=(p.instrumentos||[]).map(i=>`<tr><td><b>${esc(i.servico||'Sem tipo')}</b><br>${esc(i.tipo||'-')}: ${esc(i.numero||'-')}<br>Vigência: ${fmt(i.vigenciaFim)}</td><td>${esc(i.natureza||'-')}</td><td>${i.bloqueado?'<span class="tag bloq">Bloqueado</span><br>'+esc(i.motivoBloqueio):'<span class="tag ativo">Liberado</span>'}</td><td>${(i.procedimentos||[]).length}</td><td>${isAdmin()?`<button onclick="abrirInstrumento('${p.id}','${i.id}')">Editar</button><button onclick="duplicarInstrumento('${p.id}','${i.id}')">Duplicar</button>`:(canWrite()?`<button onclick="abrirOfertaPrestador('${p.id}','${i.id}')">Lançar procedimentos/oferta</button>`:'Consulta')}</td></tr>`).join('') || '<tr><td colspan="5">Nenhum serviço/instrumento cadastrado.</td></tr>';
  main(`<h1>${esc(p.nome)}</h1><div class="card"><p><b>Razão social:</b> ${esc(p.razaoSocial||p.nome||'-')}</p><p><b>Nome fantasia:</b> ${esc(p.nomeFantasia||p.nome||'-')}</p><p><b>Município:</b> ${esc(p.municipio)}</p><p><b>Tipo(s) de serviço:</b> ${esc(servicosPrestador(p))}</p><p><b>CNPJ:</b> ${esc(p.cnpj||'-')} &nbsp; <b>CNES:</b> ${esc(p.cnes||'-')}</p><p><b>Contato:</b> ${esc(p.responsavel||'-')} • ${esc(p.telefone||'-')} • ${esc(p.email||'-')}</p></div>${isAdmin()?`<div class="card"><h3>Editar dados do prestador</h3><div class="grid"><div><label>Razão social</label><input id="epRazao" value="${esc(p.razaoSocial||p.nome||'')}"></div><div><label>Nome fantasia</label><input id="epNome" value="${esc(p.nomeFantasia||p.nome||'')}"></div><div><label>Município</label>${selAux('municipios','epMun',p.municipio||'')}</div><div><label>CNPJ</label><input id="epCnpj" value="${esc(p.cnpj||'')}"></div><div><label>CNES</label><input id="epCnes" value="${esc(p.cnes||'')}"></div><div><label>Endereço</label><input id="epEndereco" value="${esc(p.endereco||'')}"></div><div><label>Responsável</label><input id="epResp" value="${esc(p.responsavel||'')}"></div><div><label>Telefone</label><input id="epTel" value="${esc(p.telefone||'')}"></div><div><label>E-mail</label><input id="epEmail" value="${esc(p.email||'')}"></div><div><label>Contato administrativo</label><input id="epContato" value="${esc(p.contatoAdministrativo||'')}"></div><div><label>Status</label><select id="epAtivo"><option value="true" ${p.ativo!==false?'selected':''}>Ativo</option><option value="false" ${p.ativo===false?'selected':''}>Inativo</option></select></div></div><label>Observação geral</label><input id="epObs" value="${esc(p.observacaoGeral||'')}"><button onclick="salvarPrestador('${p.id}')">Salvar dados do prestador</button></div><div class="card"><h3>Novo instrumento/serviço</h3><div class="grid"><div><label>Tipo</label>${selAux('tiposInstrumento','niTipo','CONTRATO')}</div><div><label>Natureza</label>${selAux('naturezas','niNat','CONTRATUALIZADA')}</div><div><label>Número</label><input id="niNum"></div><div><label>Serviço</label>${selAux('tiposServico','niServ')}</div><div><label>Vigência inicial</label><input id="niInicio" type="date"></div><div><label>Vigência fim</label><input id="niFim" type="date"></div><div><label>Valor global do contrato</label><input id="niValor" placeholder="R$"></div><div><label>Modo de lançamento</label><select id="niModo"><option value="QUANTITATIVO">Quantitativo mensal</option><option value="ESCALA_SUBESCALA">Escala/Subescala</option><option value="APENAS_CONTRATUAL">Apenas contratual</option></select></div><div><label>Observação</label><input id="niObs"></div><div><label>&nbsp;</label><button onclick="novoInstrumento('${p.id}')">Adicionar</button></div></div></div>`:''}<div class="card"><h3>Instrumentos e Serviços</h3><table><thead><tr><th>Serviço/Instrumento</th><th>Natureza</th><th>Status</th><th>Proced.</th><th></th></tr></thead><tbody>${inst}</tbody></table></div><button class="btn2" onclick="prestadores()">Voltar</button>`)
}
async function salvarPrestador(pid){
  await api('/api/prestadores/'+pid,{method:'PUT',body:JSON.stringify({nome:$('#epNome').value,razaoSocial:$('#epRazao')?.value||$('#epNome').value,nomeFantasia:$('#epNome').value,municipio:$('#epMun').value,cnpj:$('#epCnpj').value,cnes:$('#epCnes')?.value||'',endereco:$('#epEndereco')?.value||'',responsavel:$('#epResp')?.value||'',telefone:$('#epTel')?.value||'',email:$('#epEmail')?.value||'',contatoAdministrativo:$('#epContato')?.value||'',ativo:$('#epAtivo').value==='true',observacaoGeral:$('#epObs').value})});
  alert('Prestador atualizado.'); await load(); editarPrestador(pid);
}
async function novoInstrumento(pid){
  if(!$('#niServ').value.trim()) return alert('Informe o tipo de serviço.');
  await api(`/api/prestadores/${pid}/instrumentos`,{method:'POST',body:JSON.stringify({tipo:$('#niTipo')?.value||'CONTRATO',natureza:$('#niNat')?.value||'CONTRATUALIZADA',numero:$('#niNum')?.value||'',servico:$('#niServ').value,vigenciaInicio:$('#niInicio')?.value||'',vigenciaFim:$('#niFim')?.value||'',valorGlobal:$('#niValor')?.value||'',modoLancamento:$('#niModo')?.value||'QUANTITATIVO',observacao:$('#niObs')?.value||''})});
  await load(); editarPrestador(pid);
}
function filtrarRolModal(q){q=norm(q);document.querySelectorAll('#tblRolModal tbody tr').forEach(tr=>{tr.style.display=!q||norm(tr.innerText).includes(q)?'':'none';});}
function abrirOfertaPrestador(pid,iid){oferta(); setTimeout(()=>{ if($('#ofPrest')){$('#ofPrest').value=pid; carregarInstrumentosOferta().then(()=>{ if($('#ofInst')){$('#ofInst').value=iid; carregarProcedimentosOferta();} });}},50)}
async function duplicarInstrumento(pid,iid){const numero=prompt('Novo número do contrato/instrumento:'); if(numero===null)return; await api(`/api/prestadores/${pid}/instrumentos/${iid}/duplicar`,{method:'POST',body:JSON.stringify({numero})}); await load(); editarPrestador(pid)}
function abrirInstrumento(pid,iid){
  const p=PRESTADORES.find(x=>x.id===pid), i=p.instrumentos.find(x=>x.id===iid);
  const procs=(i.procedimentos||[]).sort((a,b)=>String(a.nome).localeCompare(String(b.nome),'pt-BR')).map(pr=>`<tr><td>${esc(pr.codigo)}</td><td>${esc(pr.nome)}</td><td>${pr.ativo!==false?'Ativo':'Inativo'}</td><td><button onclick="toggleProc('${pid}','${iid}','${pr.codigo}',${pr.ativo===false})">${pr.ativo!==false?'Inativar':'Ativar'}</button></td></tr>`).join('')||'<tr><td colspan="4">Nenhum procedimento vinculado ao contrato.</td></tr>';
  const subs=(i.subescalas||[]).sort((a,b)=>String(a.nome).localeCompare(String(b.nome),'pt-BR')).map(sub=>`<tr><td><b>${esc(sub.nome)}</b>${sub.observacao?`<br><span class="muted">${esc(sub.observacao)}</span>`:''}</td><td>${sub.ativo!==false?'Ativa':'Inativa'}</td><td><button onclick="toggleSubescala('${pid}','${iid}','${sub.id}',${sub.ativo===false})">${sub.ativo!==false?'Inativar':'Ativar'}</button></td></tr>`).join('')||'<tr><td colspan="3">Nenhuma subescala cadastrada para lançamento.</td></tr>';
  main(`<h1>${esc(i.servico||'Contrato')}</h1><p class="muted">${esc(p.nome)} • ${esc(p.municipio||'')}</p><div class="card"><h3>Dados contratuais</h3><div class="grid"><div><label>Número</label><input id="eNum" value="${esc(i.numero||'')}"></div><div><label>Processo</label><input id="eProc" value="${esc(i.processo||'')}"></div><div><label>Serviço</label>${selAux('tiposServico','eServ',i.servico||'')}</div><div><label>Vigência inicial</label><input id="eInicio" type="date" value="${i.vigenciaInicio||''}"></div><div><label>Vigência fim</label><input id="eFim" type="date" value="${i.vigenciaFim||''}"></div><div><label>Valor global do contrato</label><input id="eValor" value="${esc(i.valorGlobal||'')}" inputmode="numeric" placeholder="R$ 0,00"></div><div><label>Modo de lançamento</label><select id="eModo"><option value="QUANTITATIVO" ${(!i.modoLancamento||i.modoLancamento==='QUANTITATIVO')?'selected':''}>Quantitativo mensal</option><option value="ESCALA_SUBESCALA" ${i.modoLancamento==='ESCALA_SUBESCALA'?'selected':''}>Escala/Subescala</option><option value="APENAS_CONTRATUAL" ${i.modoLancamento==='APENAS_CONTRATUAL'?'selected':''}>Apenas contratual</option></select></div><div><label>Bloqueado</label><select id="eBloq"><option value="false">Não</option><option value="true" ${i.bloqueado?'selected':''}>Sim</option></select></div><div><label>Motivo bloqueio</label>${selAux('motivosBloqueio','eMot',i.motivoBloqueio||'')}</div><div><label>Observação</label><input id="eObs" value="${esc(i.observacao||'')}"></div></div></div><div class="grid2"><div class="card"><h3>Rol de procedimentos</h3><p class="muted">Aparece na Rede Executora. Não é usado como subescala.</p><div class="sigtap-autocomplete"><label>Procedimento SIGTAP</label><input id="buscaProc" class="full-input" list="sigtapOptions" oninput="buscarProcDebounced()" placeholder="Digite código ou nome do procedimento..."><datalist id="sigtapOptions"></datalist></div><button onclick="vincularProc('${pid}','${iid}')">Vincular procedimento</button><table><thead><tr><th>Código</th><th>Procedimento</th><th>Status</th><th></th></tr></thead><tbody>${procs}</tbody></table></div><div class="card"><h3>Subescalas de lançamento</h3><p class="muted">Aparecem para o operador preencher mensalmente. Ex.: Ortopedia, Urologia, Tomografia.</p><div class="grid"><div><label>Nova subescala</label><input id="subNome" placeholder="Ex.: Ortopedia"></div><div><label>Observação</label><input id="subObs" placeholder="Opcional"></div></div><button onclick="novaSubescala('${pid}','${iid}')">Adicionar subescala</button><table><thead><tr><th>Subescala</th><th>Status</th><th></th></tr></thead><tbody>${subs}</tbody></table></div></div><div class="card">${renderDocumentEditor(i.anexos)}</div><div class="sticky-actions"><button onclick="salvarInstrumento('${pid}','${iid}')">💾 Salvar Alterações</button><button class="btn2" onclick="confirmarCancelar(()=>editarPrestador('${pid}'))">❌ Cancelar</button></div>`); buscarProc(); bindMoneyMask('eValor');
}

async function salvarInstrumento(pid,iid){await api(`/api/prestadores/${pid}/instrumentos/${iid}`,{method:'PUT',body:JSON.stringify({numero:$('#eNum').value,processo:$('#eProc')?.value||'',servico:$('#eServ').value,vigenciaInicio:$('#eInicio')?.value||'',vigenciaFim:$('#eFim').value,valorGlobal:$('#eValor')?.value||'',modoLancamento:$('#eModo')?.value||'QUANTITATIVO',anexos:collectDocumentos(),bloqueado:$('#eBloq').value==='true',motivoBloqueio:$('#eMot').value,observacao:$('#eObs').value})}); await load(); toast('✅ Alterações salvas com sucesso.'); abrirInstrumento(pid,iid)}
let __procTimer=null;
function buscarProcDebounced(){clearTimeout(__procTimer);__procTimer=setTimeout(buscarProc,180)}
async function buscarProc(){
  const q=$('#buscaProc')?.value||'';
  const r=await api('/api/sigtap?q='+encodeURIComponent(q)).catch(()=>[]);
  const dl=$('#sigtapOptions');
  if(dl) dl.innerHTML=(r||[])
    .sort((a,b)=>String(a.nome||'').localeCompare(String(b.nome||''),'pt-BR')||String(a.codigo||'').localeCompare(String(b.codigo||''),'pt-BR'))
    .slice(0,100)
    .map(x=>`<option value="${x.codigo} - ${x.nome}"></option>`).join('');
}
async function vincularProc(pid,iid){
  const raw=($('#buscaProc')?.value||'').trim();
  if(!raw){toast('⚠️ Selecione um procedimento SIGTAP antes de vincular.','warn');return;}
  let codigo='', nome='';
  if(raw.includes('|')){[codigo,nome]=raw.split('|');}
  else { const m=raw.match(/^(\d{8,10})\s*-\s*(.+)$/); if(m){codigo=m[1];nome=m[2];} }
  if(!codigo || !nome){
    const r=await api('/api/sigtap?q='+encodeURIComponent(raw)).catch(()=>[]);
    const item=(r||[])[0];
    if(item){codigo=item.codigo;nome=item.nome;}
  }
  if(!codigo || !nome){toast('⚠️ Procedimento não localizado na base SIGTAP.','warn');return;}
  await api(`/api/prestadores/${pid}/instrumentos/${iid}/procedimentos`,{method:'POST',body:JSON.stringify({codigo,nome})});
  await load(); toast('✅ Alterações salvas com sucesso.'); abrirInstrumento(pid,iid)
}
async function toggleProc(pid,iid,cod,ativo){await api(`/api/prestadores/${pid}/instrumentos/${iid}/procedimentos/${cod}`,{method:'PUT',body:JSON.stringify({ativo})}); await load(); toast('✅ Alterações salvas com sucesso.'); abrirInstrumento(pid,iid)}
async function novaSubescala(pid,iid){const nome=$('#subNome')?.value||'';if(!nome.trim())return alert('Informe o nome da subescala.');await api(`/api/prestadores/${pid}/instrumentos/${iid}/subescalas`,{method:'POST',body:JSON.stringify({nome,observacao:$('#subObs')?.value||''})});await load();toast('✅ Subescala cadastrada com sucesso.');abrirInstrumento(pid,iid)}
async function toggleSubescala(pid,iid,sid,ativo){await api(`/api/prestadores/${pid}/instrumentos/${iid}/subescalas/${sid}`,{method:'PUT',body:JSON.stringify({ativo})});await load();toast('✅ Alterações salvas com sucesso.');abrirInstrumento(pid,iid)}
async function oferta(){
  await load();
  const opts=PRESTADORES.map(p=>`<option value="${p.id}">${optPrestador(p)}</option>`).join('');
  if(!opts){ main('<h1>Oferta Mensal</h1><div class="card"><p>Nenhum prestador vinculado ao seu usuário. Peça ao administrador para vincular uma unidade ao seu cadastro.</p></div>'); return; }
  main(`<h1>Oferta Mensal</h1><div class="card"><p class="muted">Operadores visualizam e lançam somente os prestadores vinculados ao seu usuário. Lance apenas as escalas/subescalas configuradas pela Gestão de Contratos.</p><div class="grid"><div><label>Competência</label><input id="ofMes" type="month" value="${new Date().toISOString().slice(0,7)}" onchange="carregarProcedimentosOferta()"></div><div><label>Prestador</label><select id="ofPrest" onchange="carregarInstrumentosOferta()">${opts}</select></div><div><label>Serviço/Instrumento</label><select id="ofInst" onchange="carregarProcedimentosOferta()"></select></div><div><label>&nbsp;</label><button onclick="carregarProcedimentosOferta()">Carregar</button></div></div></div><div id="totalPrestador"></div><div id="ofLista"></div>`);
  await carregarInstrumentosOferta();
}
async function carregarInstrumentosOferta(){
  const p=PRESTADORES.find(x=>x.id===$('#ofPrest')?.value);
  const inst=(p?.instrumentos||[]).filter(i=>i.ativo!==false);
  if($('#ofInst')) $('#ofInst').innerHTML=inst.map(i=>`<option value="${i.id}">${esc(i.servico||'Sem tipo')} - ${esc(i.numero||i.tipo||'')}</option>`).join('');
  await carregarProcedimentosOferta();
}
function formNovoServicoOferta(p){return `<div class="card"><h3>Adicionar serviço/instrumento para este prestador</h3><p class="muted">Antes de lançar procedimentos, a unidade precisa ter pelo menos um tipo de serviço/instrumento.</p><div class="grid"><div><label>Serviço</label>${selAux('tiposServico','ofNovoServ')}</div><div><label>Tipo</label>${selAux('tiposInstrumento','ofNovoTipo','CONTRATO')}</div><div><label>Natureza</label>${selAux('naturezas','ofNovoNat','CONTRATUALIZADA')}</div><div><label>Número</label><input id="ofNovoNum" placeholder="Opcional"></div></div><button onclick="novoInstrumentoOferta('${p?.id||''}')">Adicionar serviço</button></div>`}
async function carregarProcedimentosOferta(){
  const p=PRESTADORES.find(x=>x.id===$('#ofPrest')?.value); const mes=$('#ofMes')?.value||new Date().toISOString().slice(0,7);
  const ofertas=await api('/api/ofertas?mes='+mes).catch(()=>[]);
  const tetosMes=await api('/api/tetos?mes='+mes).catch(()=>[]);
  const totalPrestador=ofertas.filter(x=>x.prestadorId===p?.id).reduce((s,x)=>s+Number(x.quantidade||0),0);
  if($('#totalPrestador')) $('#totalPrestador').innerHTML=`<div class="card total-card"><b>Total consolidado do prestador no mês</b><h2>${totalPrestador.toLocaleString('pt-BR')}</h2><p class="muted">Soma das escalas/subescalas lançadas para ${esc(p?.nome||'')} em ${mesLabel(mes)}.</p></div>`;
  if(!p){ if($('#ofLista')) $('#ofLista').innerHTML='<div class="card">Selecione um prestador.</div>'; return; }
  const iid=$('#ofInst')?.value; const i=(p.instrumentos||[]).find(x=>x.id===iid);
  if(!i){ $('#ofLista').innerHTML='<div class="card">Nenhum serviço/contrato cadastrado para este prestador. Acione a gestão de contratos.</div>'; return; }
  const tetoServ=tetosMes.find(t=>t.modalidade==='SERVICO'&&t.prestadorId===p.id&&t.instrumentoId===i.id);
  const totalServico=ofertas.filter(x=>x.prestadorId===p.id&&x.instrumentoId===i.id).reduce((s,x)=>s+Number(x.quantidade||0),0);
  const tetoBox=tetoServ?`<div class="card teto-box"><b>Teto físico mensal do serviço</b><h2>${Number(tetoServ.quantidade||0).toLocaleString('pt-BR')}</h2><p class="muted">Lançado: ${totalServico.toLocaleString('pt-BR')} • Diferença: ${(totalServico-Number(tetoServ.quantidade||0)).toLocaleString('pt-BR')}</p>${tetoServ.observacao?`<p><b>Observação:</b> ${esc(tetoServ.observacao)}</p>`:''}</div>`:`<div class="card teto-box"><b>Teto físico mensal</b><p class="muted">Nenhum teto físico mensal definido para este prestador/tipo de serviço.</p></div>`;
  let base=(i.subescalas||[]).filter(s=>s.ativo!==false).sort((a,b)=>String(a.nome).localeCompare(String(b.nome),'pt-BR'));
  if(!base.length) base=[{id:'__principal',nome:nomeEscalaPadrao(i.servico)}];
  const html=base.map(sub=>{const codigo=sub.id||sub.nome; const o=ofertas.find(x=>x.prestadorId===p.id&&x.instrumentoId===i.id&&String(x.codigo||'')===String(codigo)); return `<div class="proced-row"><div><b>${esc(sub.nome)}</b><br><span class="muted">${i.modoLancamento==='ESCALA_SUBESCALA'?'Subescala':'Quantitativo direto'}${sub.observacao?` • ${esc(sub.observacao)}`:''}</span></div><input class="qtd" data-codigo="${esc(codigo)}" data-nome="${esc(sub.nome)}" type="number" min="0" value="${o?Number(o.quantidade||0):0}"><input class="obs" data-codigo="${esc(codigo)}" placeholder="Observação" value="${esc(o?.observacao||'')}"></div>`}).join('')||'<p class="muted">Nenhuma subescala cadastrada. Acione a gestão de contratos para configurar as subescalas deste serviço.</p>';
  $('#ofLista').innerHTML=`${tetoBox}<div class="card"><h3>${esc(i.servico||'Serviço')}</h3><p class="muted"><b>Prestador:</b> ${esc(p.nome||'')} | <b>Contrato:</b> ${esc(i.numero||'-')} | <b>Modo:</b> ${modoLancamentoLabel(i.modoLancamento)}</p>${html}<label>Justificativa/observação geral</label><input id="just" placeholder="Opcional"><button onclick="salvarOferta()">Salvar escala/oferta</button></div><div class="card"><p class="muted">O rol de procedimentos contratual é cadastrado pelo Administrador e aparece na Rede Executora. O operador lança apenas escalas/subescalas.</p></div>`;
}
async function novoInstrumentoOferta(pid){
  if(!pid) return alert('Selecione um prestador.');
  if(!$('#ofNovoServ').value.trim()) return alert('Informe o serviço.');
  await api(`/api/prestadores/${pid}/instrumentos`,{method:'POST',body:JSON.stringify({tipo:$('#ofNovoTipo').value,natureza:$('#ofNovoNat').value,numero:$('#ofNovoNum').value,servico:$('#ofNovoServ').value})});
  alert('Serviço adicionado. Agora vincule os procedimentos.'); await load(); await carregarInstrumentosOferta();
}
async function salvarOferta(){
  const itens=[...document.querySelectorAll('.qtd')].map(el=>({codigo:el.dataset.codigo,nome:el.dataset.nome,quantidade:el.value,observacao:document.querySelector(`.obs[data-codigo="${CSS.escape(el.dataset.codigo)}"]`)?.value||''}));
  if(!itens.length) return alert('Vincule ao menos um procedimento antes de salvar a oferta.');
  const r=await api('/api/ofertas/lote',{method:'POST',body:JSON.stringify({mes:$('#ofMes').value,prestadorId:$('#ofPrest').value,instrumentoId:$('#ofInst').value,itens,justificativa:$('#just')?.value||''})});
  toast('✅ Oferta salva com sucesso. Total consolidado do prestador no mês: '+(r.totalPrestadorMes??'')); await carregarProcedimentosOferta();
}
async function buscarProcOferta(){
  const q=$('#ofBuscaProc')?.value||''; const r=await api('/api/sigtap?q='+encodeURIComponent(q)).catch(()=>[]); const sel=$('#ofSelProc');
  if(sel) sel.innerHTML=(r||[]).sort((a,b)=>String(a.nome||'').localeCompare(String(b.nome||''),'pt-BR')||String(a.codigo||'').localeCompare(String(b.codigo||''),'pt-BR')).slice(0,80).map(x=>`<option value="${esc(x.codigo)}|${esc(String(x.nome))}">${esc(x.codigo)} - ${esc(x.nome)}</option>`).join('') || '<option value="">Nenhum procedimento encontrado</option>';
}
async function vincularProcOferta(){
  const v=$('#ofSelProc')?.value; if(!v)return alert('Selecione um procedimento.'); const [codigo,...rest]=v.split('|'); const nome=rest.join('|');
  if(!codigo || !nome) return alert('Procedimento inválido.');
  await api(`/api/prestadores/${$('#ofPrest').value}/instrumentos/${$('#ofInst').value}/procedimentos`,{method:'POST',body:JSON.stringify({codigo,nome})});
  alert('Procedimento vinculado. Agora informe o quantitativo e salve.'); await load(); await carregarInstrumentosOferta();
}

async function tetosMensais(){
  await load();
  if(!isAdmin()) return main('<h1>Tetos mensais</h1><div class="card">Apenas administrador pode gerenciar tetos mensais.</div>');
  const prestOpts=PRESTADORES.map(p=>`<option value="${p.id}">${optPrestador(p)}</option>`).join('');
  const rows=(TETOS||[]).slice().sort((a,b)=>String(a.prestador).localeCompare(String(b.prestador),'pt-BR')).map(t=>`<tr><td><b>${esc(t.prestador||'')}</b><br><span class="muted">${esc(t.municipio||'')} • ${esc(t.servico||'')}</span></td><td>${t.modalidade==='PROCEDIMENTO'?'Procedimento':'Serviço/Grupo'}${t.codigo?`<br><span class="muted">${esc(t.codigo)} - ${esc(t.procedimento||'')}</span>`:''}</td><td>${Number(t.quantidade||0).toLocaleString('pt-BR')}</td><td>${esc(t.inicio||'-')} até ${esc(t.fim||'indeterminado')}</td><td>${t.ativo!==false?'Ativo':'Inativo'}</td><td><button onclick="editarTeto('${t.id}')">Editar</button></td></tr>`).join('')||'<tr><td colspan="6">Nenhum teto cadastrado.</td></tr>';
  main(`<h1>Tetos mensais</h1><div class="card"><h3>Novo teto</h3><p class="muted">Use modalidade <b>Serviço/Grupo</b> para diagnóstico ou quando o teto for consolidado da prestadora. Use <b>Procedimento</b> somente quando houver referência específica para um procedimento.</p><div class="grid"><div><label>Prestador</label><select id="tPrest" onchange="carregarInstrumentosTeto()">${prestOpts}</select></div><div><label>Serviço</label><select id="tInst" onchange="carregarProcedimentosTeto()"></select></div><div><label>Modalidade</label><select id="tMod" onchange="carregarProcedimentosTeto()"><option value="SERVICO">Serviço/Grupo</option><option value="PROCEDIMENTO">Procedimento</option></select></div><div><label>Procedimento</label><select id="tProc"></select></div><div><label>Teto mensal</label><input id="tQtd" type="number" min="0"></div><div><label>Competência inicial</label><input id="tIni" type="month" value="${new Date().toISOString().slice(0,7)}"></div><div><label>Competência final</label><input id="tFim" type="month"></div><div><label>Ativo</label><select id="tAtivo"><option value="true">Sim</option><option value="false">Não</option></select></div></div><label>Observação da referência</label><input id="tObs" placeholder="Ex.: Conforme tabela de redistribuição pactuada"><button onclick="salvarTeto()">Salvar teto</button></div><div class="card"><h3>Tetos cadastrados</h3><table><thead><tr><th>Prestador/serviço</th><th>Modalidade</th><th>Teto</th><th>Vigência</th><th>Status</th><th></th></tr></thead><tbody>${rows}</tbody></table></div>`);
  carregarInstrumentosTeto();
}
function carregarInstrumentosTeto(){
  const p=PRESTADORES.find(x=>x.id===$('#tPrest')?.value); const inst=(p?.instrumentos||[]).filter(i=>i.ativo!==false);
  if($('#tInst')) $('#tInst').innerHTML=inst.map(i=>`<option value="${i.id}">${esc(i.servico||'Sem tipo')} - ${esc(i.numero||i.tipo||'')}</option>`).join('');
  carregarProcedimentosTeto();
}
function carregarProcedimentosTeto(){
  const p=PRESTADORES.find(x=>x.id===$('#tPrest')?.value); const i=(p?.instrumentos||[]).find(x=>x.id===$('#tInst')?.value); const mod=$('#tMod')?.value||'SERVICO';
  if($('#tProc')){ $('#tProc').disabled = mod!=='PROCEDIMENTO'; $('#tProc').innerHTML=(i?.procedimentos||[]).filter(pr=>pr.ativo!==false).map(pr=>`<option value="${esc(pr.codigo)}|${esc(pr.nome)}">${esc(pr.codigo)} - ${esc(pr.nome)}</option>`).join('') || '<option value="">Sem procedimento vinculado</option>'; }
}
async function salvarTeto(){
  const mod=$('#tMod').value; let codigo='', procedimento='';
  if(mod==='PROCEDIMENTO'){ const v=$('#tProc').value||''; [codigo,...rest]=v.split('|'); procedimento=rest.join('|'); if(!codigo) return alert('Selecione o procedimento.'); }
  if(!$('#tQtd').value) return alert('Informe o teto mensal.');
  await api('/api/tetos',{method:'POST',body:JSON.stringify({prestadorId:$('#tPrest').value,instrumentoId:$('#tInst').value,modalidade:mod,codigo,procedimento,quantidade:$('#tQtd').value,inicio:$('#tIni').value,fim:$('#tFim').value,observacao:$('#tObs').value,ativo:$('#tAtivo').value==='true'})});
  alert('Teto salvo.'); tetosMensais();
}
async function editarTeto(id){
  await load(); const t=TETOS.find(x=>x.id===id); if(!t) return alert('Teto não encontrado.');
  main(`<h1>Editar teto</h1><div class="card"><p><b>${esc(t.prestador)}</b><br>${esc(t.servico)} • ${t.modalidade==='PROCEDIMENTO'?esc((t.codigo||'')+' - '+(t.procedimento||'')):'Serviço/Grupo'}</p><div class="grid"><div><label>Teto mensal</label><input id="etQtd" type="number" value="${Number(t.quantidade||0)}"></div><div><label>Competência inicial</label><input id="etIni" type="month" value="${esc(t.inicio||'')}"></div><div><label>Competência final</label><input id="etFim" type="month" value="${esc(t.fim||'')}"></div><div><label>Ativo</label><select id="etAtivo"><option value="true" ${t.ativo!==false?'selected':''}>Sim</option><option value="false" ${t.ativo===false?'selected':''}>Não</option></select></div></div><label>Observação</label><input id="etObs" value="${esc(t.observacao||'')}"><button onclick="salvarEdicaoTeto('${id}')">Salvar alterações</button><button class="btn2" onclick="tetosMensais()">Voltar</button></div>`);
}
async function salvarEdicaoTeto(id){ await api('/api/tetos/'+id,{method:'PUT',body:JSON.stringify({quantidade:$('#etQtd').value,inicio:$('#etIni').value,fim:$('#etFim').value,ativo:$('#etAtivo').value==='true',observacao:$('#etObs').value})}); alert('Teto atualizado.'); tetosMensais(); }
function sigtap(){main(`<h1>Base SIGTAP única</h1><p class="muted">Cadastro central de procedimentos. O rol dos contratos e a Rede Executora usam esta mesma base, evitando duplicidade.</p><div class="grid2"><div class="card"><h3>Cadastrar procedimento individual</h3><div class="grid"><div><label>Código</label><input id="sgCod"></div><div><label>Nome</label><input id="sgNome"></div><div><label>Grupo</label><input id="sgGrupo"></div><div><label>Subgrupo</label><input id="sgSub"></div></div><button onclick="novoSigtap()">Cadastrar</button></div><div class="card"><h3>Importar TXT</h3><p class="muted">Envie arquivo com colunas COD. SIGTAP e DESC. SIGTAP. O sistema registra apenas códigos que ainda não existem.</p><div class="grid"><div><label>Arquivo TXT</label><input id="sgFile" type="file" accept=".txt,text/plain"></div><div><label>Grupo padrão</label><input id="sgImpGrupo" value="IMPORTADO"></div><div><label>Subgrupo padrão</label><input id="sgImpSub" value="TXT"></div><div><label>Descrição existente</label><select id="sgAtualizar"><option value="false">Manter descrição atual</option><option value="true">Atualizar descrição se mudar</option></select></div></div><button onclick="importarSigtapTxt()">Importar base TXT</button><div id="sgImportResumo"></div></div></div><div class="card"><h3>Procedimentos cadastrados</h3><input id="sgBusca" oninput="listarSigtap()" placeholder="Buscar código, procedimento, grupo ou subgrupo"><div id="sgLista"></div></div><div class="card"><h3>Histórico de importações</h3><div id="sgHistorico"></div></div>`); listarSigtap(); listarImportacoesSigtap()}
async function novoSigtap(){await api('/api/sigtap',{method:'POST',body:JSON.stringify({codigo:$('#sgCod').value,nome:$('#sgNome').value,grupo:$('#sgGrupo').value,subgrupo:$('#sgSub').value})}); $('#sgCod').value='';$('#sgNome').value=''; listarSigtap()}
async function listarSigtap(){const r=await api('/api/sigtap?q='+encodeURIComponent($('#sgBusca')?.value||'')); $('#sgLista').innerHTML=`<p class="muted">${r.length.toLocaleString('pt-BR')} procedimento(s) encontrado(s).</p><table><thead><tr><th>Código</th><th>Procedimento</th><th>Grupo/Subgrupo</th></tr></thead><tbody>${r.slice(0,300).map(x=>`<tr><td>${esc(x.codigo)}</td><td>${esc(x.nome)}</td><td>${esc(x.grupo||'')}${x.subgrupo?`<br><span class="muted">${esc(x.subgrupo)}</span>`:''}</td></tr>`).join('')}</tbody></table>${r.length>300?'<p class="muted">Exibindo os primeiros 300. Use a busca para refinar.</p>':''}`}
async function importarSigtapTxt(){const f=$('#sgFile').files[0]; if(!f)return alert('Selecione um arquivo TXT.'); const conteudo=await f.text(); const resumo=await api('/api/sigtap/importar-txt',{method:'POST',body:JSON.stringify({arquivo:f.name,conteudo,grupo:$('#sgImpGrupo').value,subgrupo:$('#sgImpSub').value,atualizarDescricoes:$('#sgAtualizar').value==='true'})}); $('#sgImportResumo').innerHTML=`<div class="msg ok"><b>Importação concluída</b><br>Total lido: ${resumo.totalLido}<br>Novos cadastrados: ${resumo.novosCadastrados}<br>Já existentes: ${resumo.jaExistentes}<br>Atualizados: ${resumo.atualizados}<br>Erros: ${resumo.erros}</div>`; await load(); listarSigtap(); listarImportacoesSigtap();}
async function listarImportacoesSigtap(){const h=await api('/api/sigtap/importacoes').catch(()=>[]); const el=$('#sgHistorico'); if(!el)return; el.innerHTML=`<table><thead><tr><th>Data</th><th>Arquivo</th><th>Usuário</th><th>Lido</th><th>Novos</th><th>Existentes</th><th>Atualizados</th><th>Erros</th></tr></thead><tbody>${h.slice(0,20).map(i=>`<tr><td>${cell(i.dataHora)}</td><td>${esc(i.arquivo)}</td><td>${esc(i.usuario)}</td><td>${i.totalLido}</td><td>${i.novosCadastrados}</td><td>${i.jaExistentes}</td><td>${i.atualizados}</td><td>${i.erros}</td></tr>`).join('')}</tbody></table>`}
let REL_ATUAL={titulo:'',linhas:[]};
function periodo(){const i=$('#ri')?.value||new Date().toISOString().slice(0,7),f=$('#rf')?.value||i;return{inicio:i,fim:f,inicioDia:i+'-01',fimDia:f+'-31'}}
async function relatorios(){main(`<h1>Relatórios</h1><div class="card"><div class="grid"><div><label>Início</label><input id="ri" type="month" value="${new Date().toISOString().slice(0,7)}"></div><div><label>Fim</label><input id="rf" type="month" value="${new Date().toISOString().slice(0,7)}"></div><div><label>&nbsp;</label><button onclick="gerarRelatorio()">Resumo geral</button></div><div><label>&nbsp;</label><button onclick="baixarExcel()">Baixar Excel</button></div></div></div><div class="card"><h2>Relatórios completos</h2><div class="report-grid"><button onclick="relResumoProcedimentos()">Resumo por procedimentos</button><button onclick="relPrestadores()">Resumo por prestadores</button><button onclick="relMunicipios()">Resumo por municípios</button><button onclick="relServicos()">Resumo por serviços</button><button onclick="relProducaoOperadores()">Produção dos operadores</button><button onclick="relAuditoriaDetalhada()">Auditoria detalhada</button><button onclick="relBloqueios()">Bloqueios ativos</button><button onclick="relVigencias()">Vigências críticas</button><button onclick="relSemOferta()">Procedimentos sem oferta</button><button onclick="relPanoramaMacro()">Panorama Macro 1 e Macro 2</button><button onclick="relEscalasLancadas()">Escalas lançadas/pendentes</button><button onclick="relTetosMensais()">Tetos x lançamento</button></div></div><div id="rel"></div>`); gerarRelatorio()}
function relActions(){return `<div class="row"><button onclick="printRelatorio()">Imprimir</button><button onclick="csvRelatorio()">Exportar CSV</button></div>`}
function setRel(titulo,html,linhas=[]){REL_ATUAL={titulo,linhas};$('#rel').innerHTML=`<div class="card"><h2>${titulo}</h2>${relActions()}</div>${html}`}
function objRows(obj,cols=['Item','Total']){return Object.entries(obj||{}).sort((a,b)=>Number(b[1])-Number(a[1])||String(a[0]).localeCompare(String(b[0]),'pt-BR')).map(([k,v])=>({[cols[0]]:k,[cols[1]]:v}))}
function tableRows(rows){if(!rows.length)return '<p class="muted">Nenhum registro encontrado.</p>';const cols=Object.keys(rows[0]);return `<table><thead><tr>${cols.map(c=>`<th>${c}</th>`).join('')}</tr></thead><tbody>${rows.map(r=>`<tr>${cols.map(c=>`<td>${cell(r[c])}</td>`).join('')}</tr>`).join('')}</tbody></table>`}
async function gerarRelatorio(){const p=periodo();const r=await api(`/api/relatorios/resumo?inicio=${p.inicio}&fim=${p.fim}`); const cards=`<div class="grid"><div class="card"><b>Total ofertado</b><h2>${r.total}</h2></div><div class="card"><b>Procedimentos</b><h2>${Object.keys(r.porProcedimento||{}).length}</h2></div><div class="card"><b>Prestadores</b><h2>${Object.keys(r.porPrestador||{}).length}</h2></div><div class="card"><b>Municípios</b><h2>${Object.keys(r.porMunicipio||{}).length}</h2></div></div>`; const linhas=[...objRows(r.porProcedimento,['Procedimento','Total'])]; setRel('Resumo geral do período',cards+`<div class="grid2"><div class="card"><h3>Por procedimento</h3>${tableRows(objRows(r.porProcedimento,['Procedimento','Total']))}</div><div class="card"><h3>Por prestador</h3>${tableRows(objRows(r.porPrestador,['Prestador','Total']))}</div><div class="card"><h3>Por município</h3>${tableRows(objRows(r.porMunicipio,['Município','Total']))}</div><div class="card"><h3>Por serviço</h3>${tableRows(objRows(r.porServico,['Serviço','Total']))}</div></div>`,linhas)}
async function relResumoProcedimentos(){const p=periodo(),r=await api(`/api/relatorios/resumo?inicio=${p.inicio}&fim=${p.fim}`);const rows=objRows(r.porProcedimento,['Procedimento','Total ofertado']);setRel('Resumo por procedimentos',`<div class="card"><p>Soma o quantitativo lançado por todos os prestadores em cada procedimento.</p>${tableRows(rows)}</div>`,rows)}
async function relPrestadores(){const p=periodo(),r=await api(`/api/relatorios/resumo?inicio=${p.inicio}&fim=${p.fim}`);const rows=objRows(r.porPrestador,['Prestador','Total ofertado']);setRel('Resumo por prestadores',`<div class="card">${tableRows(rows)}</div>`,rows)}
async function relMunicipios(){const p=periodo(),r=await api(`/api/relatorios/resumo?inicio=${p.inicio}&fim=${p.fim}`);const rows=objRows(r.porMunicipio,['Município','Total ofertado']);setRel('Resumo por municípios',`<div class="card">${tableRows(rows)}</div>`,rows)}
async function relServicos(){const p=periodo(),r=await api(`/api/relatorios/resumo?inicio=${p.inicio}&fim=${p.fim}`);const rows=objRows(r.porServico,['Serviço','Total ofertado']);setRel('Resumo por serviços',`<div class="card">${tableRows(rows)}</div>`,rows)}
async function relProducaoOperadores(){const p=periodo();const dados=await api(`/api/relatorios/producao-operadores?inicio=${p.inicioDia}&fim=${p.fimDia}`);const rows=(dados||[]).map(x=>({Operador:x.nome||x.usuario,Login:x.usuario,Total:x.total,...(x.acoes||{})})).sort((a,b)=>Number(b.Total)-Number(a.Total));setRel('Produção dos operadores',`<div class="card"><p>Consolida ações registradas na auditoria: lançamentos, alterações, cadastros, bloqueios e vínculos.</p>${tableRows(rows)}</div>`,rows)}
async function relAuditoriaDetalhada(){const logs=await api('/api/auditoria');const p=periodo();const rows=(logs||[]).filter(l=>(!p.inicioDia||l.dataHora>=p.inicioDia)&&(!p.fimDia||l.dataHora<=p.fimDia+'T23:59:59')).map(l=>({Data:new Date(l.dataHora).toLocaleString('pt-BR'),Usuário:l.nome||l.usuario,Perfil:l.perfil,Ação:l.acao,Entidade:l.entidade||'',Detalhes:(l.detalhes||[]).map(d=>`${d.campo}: ${d.anterior??''} → ${d.novo??''}`).join(' | ')}));setRel('Auditoria detalhada',`<div class="card">${tableRows(rows)}</div>`,rows)}
async function relBloqueios(){await load();const rows=[];PRESTADORES.forEach(p=>(p.instrumentos||[]).forEach(i=>{if(p.bloqueado||i.bloqueado||p.motivoBloqueio||i.motivoBloqueio)rows.push({Prestador:p.nome,Município:p.municipio,Serviço:i.servico,Natureza:i.natureza,Motivo:p.motivoBloqueio||i.motivoBloqueio||'Bloqueado'})}));setRel('Bloqueios ativos',`<div class="card">${tableRows(rows)}</div>`,rows)}
async function relVigencias(){await load();const hoje=new Date();const rows=[];PRESTADORES.forEach(p=>(p.instrumentos||[]).forEach(i=>{if(!i.vigenciaFim)return;const d=new Date(i.vigenciaFim+'T12:00:00');const dias=Math.ceil((d-hoje)/86400000);if(dias<=60)rows.push({Prestador:p.nome,Município:p.municipio,Serviço:i.servico,Contrato:i.numero||'',Vigência:fmt(i.vigenciaFim),Dias:dias,Status:dias<0?'Vencido':'A vencer'})}));rows.sort((a,b)=>a.Dias-b.Dias);setRel('Vigências críticas',`<div class="card"><p>Contratos vencidos ou com vencimento em até 60 dias.</p>${tableRows(rows)}</div>`,rows)}
async function relSemOferta(){await load();const p=periodo();const ofertas=await api('/api/ofertas?mes='+p.fim).catch(()=>[]);const rows=[];PRESTADORES.forEach(pr=>(pr.instrumentos||[]).forEach(i=>(i.procedimentos||[]).filter(x=>x.ativo!==false).forEach(proc=>{const o=ofertas.find(x=>x.prestadorId===pr.id&&x.instrumentoId===i.id&&String(x.codigo).replace(/\D/g,'')===String(proc.codigo).replace(/\D/g,''));if(!o||Number(o.quantidade||0)<=0)rows.push({Prestador:pr.nome,Município:pr.municipio,Serviço:i.servico,Código:proc.codigo,Procedimento:proc.nome})})));setRel('Procedimentos sem oferta',`<div class="card"><p>Considera a competência final selecionada: ${mesLabel(p.fim)}.</p>${tableRows(rows)}</div>`,rows)}
function macroNome(m){const macro1=['ALTO PARAÍSO','ARIQUEMES','BURITIS','CACAULÂNDIA','CAMPO NOVO DE RONDÔNIA','CANDEIAS DO JAMARI','CUJUBIM','GOVERNADOR JORGE TEIXEIRA','GUAJARÁ-MIRIM','ITAPUÃ DO OESTE','JARU','MACHADINHO DO OESTE','MONTE NEGRO','NOVA MAMORÉ','PORTO VELHO','RIO CRESPO','THEOBROMA','VALE DO ANARI'];return macro1.includes(String(m||'').toUpperCase())?'Macro 1':'Macro 2'}
async function relPanoramaMacro(){await load();const map={};PRESTADORES.forEach(p=>(p.instrumentos||[]).forEach(i=>{const ma=macroNome(p.municipio);if(!map[ma])map[ma]={Macro:ma,Municípios:new Set(),Prestadores:new Set(),Serviços:0,Procedimentos:0,Bloqueios:0};map[ma].Municípios.add(p.municipio);map[ma].Prestadores.add(p.nome);map[ma].Serviços++;map[ma].Procedimentos+=(i.procedimentos||[]).length;if(p.bloqueado||i.bloqueado)map[ma].Bloqueios++}));const rows=Object.values(map).map(x=>({Macro:x.Macro,Municípios:x.Municípios.size,Prestadores:x.Prestadores.size,Serviços:x.Serviços,Procedimentos:x.Procedimentos,Bloqueios:x.Bloqueios}));setRel('Panorama Macro 1 e Macro 2',`<div class="card">${tableRows(rows)}</div>`,rows)}

async function escalasMes(){const mes=new Date().toISOString().slice(0,7); main(`<h1>Escalas do mês</h1><div class="card"><div class="grid"><div><label>Competência</label><input id="escMes" type="month" value="${mes}"></div><div><label>&nbsp;</label><button onclick="carregarEscalasMes()">Carregar</button></div></div></div><div id="escBox"></div>`); carregarEscalasMes()}
async function carregarEscalasMes(){
  const mes=$('#escMes')?.value||new Date().toISOString().slice(0,7);
  const rows=await api('/api/escalas?mes='+mes);
  const completas=rows.filter(x=>x.status==='COMPLETA').length, parciais=rows.filter(x=>x.status==='PARCIAL').length, pendentes=rows.filter(x=>x.status==='PENDENTE').length;
  $('#escBox').innerHTML=`<div class="grid"><div class="card"><b>✅ Completas</b><h2>${completas}</h2></div><div class="card"><b>⚠️ Parciais</b><h2>${parciais}</h2></div><div class="card"><b>❌ Pendentes</b><h2>${pendentes}</h2></div><div class="card"><b>Total monitorado</b><h2>${rows.length}</h2></div></div><div class="card"><h3>Situação das escalas - ${mesLabel(mes)}</h3><p class="muted">As subescalas aparecem diretamente, sem precisar clicar. Pendências aparecem primeiro.</p></div>${renderEscalasCards(rows)}`
}
async function relEscalasLancadas(){const p=periodo();const rows=await api('/api/escalas?mes='+p.fim);const out=rows.map(e=>({Prestador:e.prestador,Serviço:e.servico||'-',Município:e.municipio,Status:statusEscalaLabel(e.status),Subescalas:`${e.subescalasPreenchidas||0}/${e.totalSubescalas||0}`,Operador:e.operador||'-',Total:e.totalOfertaMes||0}));setRel('Escalas por subescalas',`<div class="card"><p>Mostra se cada prestador/serviço está completo, parcial ou pendente na competência ${mesLabel(p.fim)}.</p>${tableRows(out)}</div>${renderEscalasCards(rows)}`,out)}


async function relTetosMensais(){const p=periodo();const rows=await api('/api/tetos/resumo?mes='+p.fim);const out=rows.map(r=>({Prestador:r.prestador,Serviço:r.servico,Município:r.municipio,'Teto mensal':r.tetoMensal??'Não definido','Lançado':r.lancado,'Diferença':r.diferenca??'-','% executado':r.percentual??'-',Observação:r.observacao||''}));setRel('Tetos mensais x lançamento',`<div class="card"><p>Compara o teto mensal consolidado por prestador/tipo de serviço com o quantitativo lançado na competência ${p.fim}.</p>${tableRows(out)}</div>`,out)}
function baixarExcel(){const p=periodo();location.href=`/api/relatorios/excel?inicio=${p.inicio}&fim=${p.fim}`}
function printRelatorio(){const w=window.open('','_blank');w.document.write(`<html><head><title>${REL_ATUAL.titulo}</title><style>body{font-family:Arial;padding:20px}table{width:100%;border-collapse:collapse}td,th{border:1px solid #ddd;padding:7px;text-align:left}h1{color:#0f3b63}</style></head><body><h1>${REL_ATUAL.titulo}</h1>${$('#rel').innerHTML}<script>setTimeout(()=>print(),200)<\/script></body></html>`);w.document.close()}
function csvRelatorio(){const rows=REL_ATUAL.linhas||[];if(!rows.length)return alert('Nenhum dado para exportar.');const cols=Object.keys(rows[0]);const csv=[cols.join(';')].concat(rows.map(r=>cols.map(c=>String(r[c]??'').replace(/;/g,',')).join(';'))).join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob(['\ufeff'+csv],{type:'text/csv'}));a.download=REL_ATUAL.titulo.toLowerCase().replace(/[^a-z0-9]+/gi,'-')+'.csv';a.click();URL.revokeObjectURL(a.href)}
async function auditoria(){const r=await api('/api/auditoria'); main(`<h1>Auditoria</h1><div class="card"><table><thead><tr><th>Data</th><th>Usuário</th><th>Ação</th><th>Alterações</th></tr></thead><tbody>${r.map(l=>`<tr><td>${new Date(l.dataHora).toLocaleString()}</td><td>${l.nome}<br>${l.perfil}</td><td>${l.acao}</td><td>${(l.detalhes||[]).map(d=>`<div><b>${d.campo}</b>: ${d.anterior??''} → ${d.novo??''}</div>`).join('')}</td></tr>`).join('')}</tbody></table></div>`)}

async function auxiliares(){await load(); const tipos={municipios:'Municípios',tiposServico:'Tipos de serviço',naturezas:'Naturezas',tiposInstrumento:'Tipos de instrumento',gruposProcedimento:'Grupos de procedimento',motivosBloqueio:'Motivos de bloqueio',situacoesVigencia:'Situações de vigência'}; const cards=Object.entries(tipos).map(([tipo,titulo])=>{ const rows=(AUX[tipo]||[]).sort((a,b)=>String(a.nome).localeCompare(String(b.nome),'pt-BR')).map(x=>`<tr><td>${x.nome}${x.macro?`<br><span class="muted">${x.macro}</span>`:''}</td><td>${x.ativo!==false?'Ativo':'Inativo'}</td><td><button onclick="toggleAux('${tipo}','${x.id}',${x.ativo!==false})">${x.ativo!==false?'Inativar':'Ativar'}</button></td></tr>`).join(''); const extra=tipo==='municipios'?`<select id="macro_${tipo}"><option>Macro 1</option><option>Macro 2</option></select>`:''; return `<div class="card"><h3>${titulo}</h3><div class="grid"><input id="novo_${tipo}" placeholder="Novo item">${extra}<button onclick="novoAux('${tipo}')">Adicionar</button></div><table><tbody>${rows}</tbody></table></div>` }).join(''); main(`<h1>Cadastros auxiliares</h1><p class="muted">Gerencie as listas usadas nos cadastros. Isso padroniza município, tipo de serviço, natureza, motivo de bloqueio e relatórios.</p><div class="grid2">${cards}</div>`)}
async function novoAux(tipo){const nome=$(`#novo_${tipo}`).value; const macro=$(`#macro_${tipo}`)?.value; await api('/api/auxiliares/'+tipo,{method:'POST',body:JSON.stringify({nome,macro})}); await load(); auxiliares()}
async function toggleAux(tipo,id,ativo){await api(`/api/auxiliares/${tipo}/${id}`,{method:'PUT',body:JSON.stringify({ativo:!ativo})}); await load(); auxiliares()}

async function usuarios(){const r=await api('/api/usuarios'); await load(); const checks=(prefix,selecionados=[])=>`<div class="checks">${PRESTADORES.map(p=>`<label><input type="checkbox" class="${prefix}" value="${p.id}" ${selecionados.includes(p.id)?'checked':''}> ${p.nome} - ${p.municipio} - ${servicosPrestador(p)}</label>`).join('')}</div>`; window.checksPrestadores=checks; main(`<h1>Usuários</h1><div class="card"><h3>Novo usuário</h3><div class="grid"><input id="un" placeholder="Nome"><input id="ul" placeholder="Login"><select id="up"><option>ADMINISTRADOR</option><option>OPERADOR</option><option>AUDITOR</option><option>GESTAO</option></select><input id="us" placeholder="Senha provisória" value="123456"></div><h4>Prestadores vinculados ao operador</h4><p class="muted">Use para limitar quais unidades aparecem para o operador. Administrador e auditor continuam vendo tudo.</p>${checks('novoVinculo')}<button onclick="novoUsuario()">Criar usuário</button></div><div class="card"><table><thead><tr><th>Usuário</th><th>Perfil</th><th>Status</th><th>Vínculos</th><th>Ações</th></tr></thead><tbody>${r.map(u=>`<tr><td><b>${u.nome}</b><br>${u.login}</td><td>${u.perfil}</td><td>${u.status}</td><td>${(u.prestadoresVinculados||[]).length} prestador(es)</td><td><button onclick="editarUsuario('${u.id}')">Editar cadastro</button><button onclick="editarVinculosUsuario('${u.id}')">Vincular prestadores</button><button onclick="bloqUser('${u.id}','${u.status==='ATIVO'?'BLOQUEADO':'ATIVO'}')">${u.status==='ATIVO'?'Bloquear':'Desbloquear'}</button><button onclick="resetUser('${u.id}')">Resetar senha</button></td></tr>`).join('')}</tbody></table></div>`)}
function marcados(cls){return [...document.querySelectorAll('.'+cls+':checked')].map(x=>x.value)}
async function novoUsuario(){await api('/api/usuarios',{method:'POST',body:JSON.stringify({nome:$('#un').value,login:$('#ul').value,perfil:$('#up').value,senha:$('#us').value,prestadoresVinculados:marcados('novoVinculo')})}); usuarios()}
async function editarUsuario(id){const users=await api('/api/usuarios'); await load(); const u=users.find(x=>x.id===id); const perfis=['ADMINISTRADOR','OPERADOR','GESTAO','AUDITOR']; const status=['ATIVO','BLOQUEADO','INATIVO']; const html=PRESTADORES.map(p=>`<label><input type="checkbox" class="editVinculo" value="${p.id}" ${(u.prestadoresVinculados||[]).includes(p.id)?'checked':''}> ${p.nome} - ${p.municipio} - ${servicosPrestador(p)}</label>`).join(''); main(`<h1>Editar usuário</h1><div class="card"><div class="grid"><div><label>Nome</label><input id="euNome" value="${u.nome||''}"></div><div><label>Login</label><input id="euLogin" value="${u.login||''}"></div><div><label>Perfil</label><select id="euPerfil">${perfis.map(p=>`<option ${u.perfil===p?'selected':''}>${p}</option>`).join('')}</select></div><div><label>Status</label><select id="euStatus">${status.map(st=>`<option ${u.status===st?'selected':''}>${st}</option>`).join('')}</select></div></div><label>Motivo de bloqueio/inativação</label><input id="euMotivo" value="${u.motivoBloqueio||''}"><h3>Prestadores vinculados</h3><p class="muted">Esses vínculos restringem a visão do operador.</p><div class="checks">${html}</div><button onclick="salvarUsuarioCompleto('${id}')">Salvar cadastro</button><button class="btn2" onclick="usuarios()">Voltar</button></div>`)}
async function salvarUsuarioCompleto(id){await api('/api/usuarios/'+id,{method:'PUT',body:JSON.stringify({nome:$('#euNome').value,login:$('#euLogin').value,perfil:$('#euPerfil').value,status:$('#euStatus').value,motivoBloqueio:$('#euMotivo').value,prestadoresVinculados:marcados('editVinculo')})}); alert('Cadastro atualizado'); usuarios()}
async function editarVinculosUsuario(id){const users=await api('/api/usuarios'); await load(); const u=users.find(x=>x.id===id); const html=PRESTADORES.map(p=>`<label><input type="checkbox" class="editVinculo" value="${p.id}" ${(u.prestadoresVinculados||[]).includes(p.id)?'checked':''}> ${p.nome} - ${p.municipio} - ${servicosPrestador(p)}</label>`).join(''); main(`<h1>Vincular prestadores</h1><div class="card"><h3>${u.nome}</h3><p class="muted">Após salvar, este operador só visualizará e lançará oferta dos prestadores marcados.</p><div class="checks">${html}</div><button onclick="salvarVinculosUsuario('${id}')">Salvar vínculos</button><button class="btn2" onclick="usuarios()">Voltar</button></div>`)}
async function salvarVinculosUsuario(id){await api('/api/usuarios/'+id,{method:'PUT',body:JSON.stringify({prestadoresVinculados:marcados('editVinculo')})}); alert('Vínculos salvos'); usuarios()}
async function bloqUser(id,status){await api('/api/usuarios/'+id,{method:'PUT',body:JSON.stringify({status,motivoBloqueio:status==='BLOQUEADO'?prompt('Motivo do bloqueio')||'':''})}); usuarios()}
async function resetUser(id){const nova=prompt('Nova senha provisória','123456'); if(!nova)return; await api('/api/usuarios/'+id,{method:'PUT',body:JSON.stringify({resetarSenha:true,novaSenha:nova})}); alert('Senha resetada')}
function perfil(){main(`<h1>Minha senha</h1><div class="card"><label>Senha atual</label><input id="sa" type="password"><label>Nova senha</label><input id="ns" type="password"><button onclick="trocarSenha()">Alterar senha</button></div>`)}
async function trocarSenha(){await api('/api/minha-senha',{method:'POST',body:JSON.stringify({senhaAtual:$('#sa').value,novaSenha:$('#ns').value})}); alert('Senha alterada')}
init();
